export const typeMismatchError = ({ path, property, typeName, value })=>{
    return {
        details: `The type of "${property}" is incorrect, expected type: ${typeName}`,
        name: 'type',
        path: path.toArray(),
        type: typeName,
        value
    };
};
export const minSizeError = ({ min, value, path })=>{
    return {
        name: 'size',
        min,
        path: path.toArray(),
        details: `Size must be at least ${min}`,
        value
    };
};
export const maxSizeError = ({ max, value, path })=>{
    return {
        name: 'size',
        max,
        path: path.toArray(),
        details: `Size must be at most ${max}`,
        value
    };
};
export const enumError = ({ expected, value, path })=>{
    return {
        details: `Value must be one of expected values`,
        name: 'in',
        expected: [
            ...expected
        ].sort(),
        path: path.toArray(),
        value
    };
};
export const unknownPropertyError = ({ property, path })=>{
    return {
        details: `The property "${property}" is not expected`,
        name: 'unexpected',
        path: path.toArray()
    };
};
export const requiredPropertyError = ({ property, path })=>{
    return {
        details: `The property "${property}" is required here`,
        name: 'required',
        path: path.toArray()
    };
};
